// // This module implements a 3-bit binary counter with an enable signal and asynchronous clear. The counter decrements its value on every positive edge of the clock when the enable signal (en) is high. If the clear signal (clr) is high, the counter resets to 0 immediately.
module counter_3bit (clk, clr, en, q);
   input clk, clr, en;
   output [2:0] q;

   reg [2:0] q;

always @(posedge clk or posedge clr) begin
    if (clr) begin
        q <= 3'b000;
    end else if (en) begin
        q <= q + 1;
    end
end

endmodule
